


// ---------------------------------------------------------------------------
// One-time (re-runnable) generator for the "fun-extra" command batch.
//
// Reads src/bot/commands/fun-extra/definitions.js and writes one small
// command file per definition into src/bot/commands/fun-extra/generated/.
// Each generated file just requires the shared factory + its own definition
// and re-exports { data, execute } - this is what the runtime command
// loader (src/bot/utils/commandLoader.js) actually discovers and loads.
//
// The loader does not support a single file exporting an array of commands,
// so rather than changing that shared loader (used by every command in the
// bot) this script pre-expands the array into individual files once.
//
// Usage: node scripts/generate-fun-commands.js
// ---------------------------------------------------------------------------

const fs = require('fs');
const path = require('path');

const definitions = require('../src/bot/commands/fun-extra/definitions.js');

const outputDir = path.join(__dirname, '..', 'src', 'bot', 'commands', 'fun-extra', 'generated');

function fileHeader() {
  return [
    '// AUTO-GENERATED by scripts/generate-fun-commands.js - do not edit by hand.',
    '// Edit src/bot/commands/fun-extra/definitions.js and re-run the generator instead.',
    '',
  ].join('\n');
}

function buildFileContent(name) {
  return `${fileHeader()}const { createFunCommand } = require('../../../utils/funCommandFactory');
const definitions = require('../definitions');

const definition = definitions.find((entry) => entry.name === '${name}');

if (!definition) {
  throw new Error('fun-extra: missing definition for "${name}" - run scripts/generate-fun-commands.js again.');
}

module.exports = createFunCommand(definition);
`;
}

function main() {
  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  const seen = new Set();
  const generated = [];

  for (const definition of definitions) {
    if (!definition || !definition.name) continue;

    if (seen.has(definition.name)) {
      throw new Error(`Duplicate fun-extra definition name: ${definition.name}`);
    }
    seen.add(definition.name);

    const filePath = path.join(outputDir, `${definition.name}.js`);
    fs.writeFileSync(filePath, buildFileContent(definition.name), 'utf8');
    generated.push(definition.name);
  }

  // Remove stale generated files for definitions that no longer exist.
  const existingFiles = fs.readdirSync(outputDir).filter((f) => f.endsWith('.js'));
  let removed = 0;
  for (const file of existingFiles) {
    const name = file.replace(/\.js$/, '');
    if (!seen.has(name)) {
      fs.unlinkSync(path.join(outputDir, file));
      removed++;
    }
  }

  console.log(`Generated ${generated.length} fun-extra command files in ${path.relative(process.cwd(), outputDir)}`);
  if (removed > 0) {
    console.log(`Removed ${removed} stale generated file(s).`);
  }
}

main();
